def add(paths):
    repo.index.add(paths)

def commit(message):
    repo.index.commit(message)

def checkout(branch):
    repo.git.checkout(branch)

def merge(branch):
    repo.merge(branch)

def clone(url):
    Repo.clone_from(url, '/tmp/myrepo')

def push():
    origin = repo.remote('origin')
    origin.push()

def pull():
    origin = repo.remote('origin')
    origin.pull()

